import{_ as a,o as i,c as s,a2 as t}from"./chunks/framework.HMsj64NP.js";const k=JSON.parse('{"title":"CMakeLists.txt","description":"","frontmatter":{},"headers":[],"relativePath":"guide/CMakeLists.md","filePath":"guide/CMakeLists.md"}'),o={name:"guide/CMakeLists.md"};function d(n,e,r,c,l,p){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="cmakelists-txt" tabindex="-1">CMakeLists.txt <a class="header-anchor" href="#cmakelists-txt" aria-label="Permalink to &quot;CMakeLists.txt&quot;">​</a></h1><p>Todo proyecto basado en el Raspberry Pi Pico SDK depende de un único <code>CMakeLists.txt</code> que decide qué se compila, para qué placa, y con qué librerías del SDK se enlaza. A diferencia de un <code>CMakeLists.txt</code> genérico de C/C++, este trae varias funciones propias del SDK (<code>pico_sdk_init</code>, <code>pico_add_extra_outputs</code>, etc.) que no existen en CMake puro.</p><div class="language-cmake vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmake</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">cmake_minimum_required</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">VERSION</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 3.20)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">include</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;${CMAKE_CURRENT_LIST_DIR}/../pico_sdk_import.cmake&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">PROJECT_NAME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;mi_proyecto&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(PROJECT_SOURCES </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mi_proyecto.c&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(PICO_BOARD      </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pico&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(PROJECT_LIBS</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    pico_stdlib</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    hardware_adc</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">project</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">${PROJECT_NAME}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C CXX ASM)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pico_sdk_init()</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add_executable</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">${PROJECT_NAME}</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ${PROJECT_SOURCES}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">target_link_libraries</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">${PROJECT_NAME}</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ${PROJECT_LIBS}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pico_add_extra_outputs(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">${PROJECT_NAME}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><hr><h2 id="cmake-minimum-required-version-3-20" tabindex="-1"><code>cmake_minimum_required(VERSION 3.20)</code> <a class="header-anchor" href="#cmake-minimum-required-version-3-20" aria-label="Permalink to &quot;`cmake_minimum_required(VERSION 3.20)`&quot;">​</a></h2><p>Fija la versión mínima de CMake compatible con las funciones del SDK. Las versiones más recientes del pico-sdk (2.x) validan además un rango superior — por ejemplo <code>VERSION 3.13...3.27</code> — para advertir si CMake ya cambió de comportamiento en versiones muy nuevas. Sin esta línea, un CMake demasiado viejo falla más adelante con errores confusos en vez de indicar directamente la incompatibilidad.</p><h2 id="include-cmake-current-list-dir-pico-sdk-import-cmake" tabindex="-1"><code>include(&quot;${CMAKE_CURRENT_LIST_DIR}/../pico_sdk_import.cmake&quot;)</code> <a class="header-anchor" href="#include-cmake-current-list-dir-pico-sdk-import-cmake" aria-label="Permalink to &quot;`include(&quot;${CMAKE_CURRENT_LIST_DIR}/../pico_sdk_import.cmake&quot;)`&quot;">​</a></h2><p>Localiza el SDK en el sistema, antes de que exista cualquier noción de &quot;proyecto&quot; para CMake. Internamente busca, en este orden de prioridad:</p><ul><li>La variable de entorno <code>PICO_SDK_PATH</code></li><li>Una variable de CMake ya cacheada con ese mismo nombre</li><li>Una carpeta <code>pico-sdk/</code> junto al proyecto (patrón de submódulo)</li><li>Si <code>PICO_SDK_FETCH_FROM_GIT</code> está activado, lo clona automáticamente desde GitHub</li></ul><p>Debe ir siempre antes de <code>project()</code>. Es la única regla de orden verdaderamente estricta en todo el archivo — casi todo lo demás se acomoda solo.</p><blockquote><p><strong>Importante — cambio de comportamiento desde el SDK 2.0.0:</strong> si tu proyecto necesita fijar <code>PICO_BOARD</code> a algo distinto de <code>pico</code> (por ejemplo <code>pico2</code> o <code>pico_w</code>), esa línea debe ir <strong>antes</strong> de este <code>include</code>, no después. En versiones anteriores del SDK bastaba con ponerlo antes de <code>pico_sdk_init()</code>, pero desde la 2.0.0 el valor se ignora silenciosamente si se declara después del <code>include</code> — el build compila igual, sin error, pero como si fuera un <code>pico</code> normal.</p></blockquote><h2 id="set-project-name-mi-proyecto" tabindex="-1"><code>set(PROJECT_NAME &quot;mi_proyecto&quot;)</code> <a class="header-anchor" href="#set-project-name-mi-proyecto" aria-label="Permalink to &quot;`set(PROJECT_NAME &quot;mi_proyecto&quot;)`&quot;">​</a></h2><p>Variable interna de conveniencia, no reservada por CMake ni por el SDK. Se reutiliza en el resto del archivo (<code>project()</code>, <code>add_executable()</code>, etc.) para que cambiar el nombre del proyecto se reduzca a editar una sola línea.</p><h2 id="set-project-sources-mi-proyecto-c-o-set-project-sources-mi-proyecto-c-mi-proyecto2-c" tabindex="-1"><code>set(PROJECT_SOURCES &quot;mi_proyecto.c&quot;)</code> o <code>set(PROJECT_SOURCES &quot;mi_proyecto.c mi_proyecto2.c&quot;)</code> <a class="header-anchor" href="#set-project-sources-mi-proyecto-c-o-set-project-sources-mi-proyecto-c-mi-proyecto2-c" aria-label="Permalink to &quot;`set(PROJECT_SOURCES &quot;mi_proyecto.c&quot;)` o `set(PROJECT_SOURCES &quot;mi_proyecto.c mi_proyecto2.c&quot;)`&quot;">​</a></h2><p>Lista de archivos fuente que se compilan. Para proyectos de un solo archivo basta con la cadena directa; si el proyecto crece a varios <code>.c</code>/<code>.cpp</code>, se convierte en lista:</p><div class="language-cmake vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmake</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(PROJECT_SOURCES</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    main.c</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sensores.c</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    utilidades.c</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="set-pico-board-pico" tabindex="-1"><code>set(PICO_BOARD &quot;pico&quot;)</code> <a class="header-anchor" href="#set-pico-board-pico" aria-label="Permalink to &quot;`set(PICO_BOARD &quot;pico&quot;)`&quot;">​</a></h2><p>Le indica al SDK para qué placa física se compila. Este valor determina, entre otras cosas: los pines por defecto de UART/I2C, si se incluye o no el soporte de radio (Wi-Fi/Bluetooth), y qué plataforma de chip (<code>PICO_PLATFORM</code>) se usa por debajo.</p><table tabindex="0"><thead><tr><th>Valor</th><th>Chip</th><th>Wireless</th><th>Uso típico</th></tr></thead><tbody><tr><td><code>pico</code></td><td>RP2040</td><td>No</td><td>Placa original, la más común</td></tr><tr><td><code>pico_w</code></td><td>RP2040</td><td>Sí (Wi-Fi/BT vía CYW43)</td><td>Proyectos con conectividad</td></tr><tr><td><code>pico2</code></td><td>RP2350</td><td>No</td><td>Nueva generación, más rápida y con más RAM</td></tr><tr><td><code>pico2_w</code></td><td>RP2350</td><td>Sí</td><td>Nueva generación + conectividad</td></tr></tbody></table><p>El SDK también trae definiciones para decenas de placas de terceros (Adafruit, SparkFun, Pimoroni, Olimex, entre otras) — la lista completa vive en el propio código fuente del SDK, en <code>src/boards/include/boards/</code>, un archivo de cabecera por cada placa soportada.</p><h2 id="set-project-libs-pico-stdlib" tabindex="-1"><code>set(PROJECT_LIBS pico_stdlib ...)</code> <a class="header-anchor" href="#set-project-libs-pico-stdlib" aria-label="Permalink to &quot;`set(PROJECT_LIBS pico_stdlib ...)`&quot;">​</a></h2><p>Librerías del SDK que se enlazan al ejecutable. <code>pico_stdlib</code> es la base casi universal (incluye <code>stdio</code>, GPIO básico, <code>sleep_ms</code>, etc.); el resto se agrega según el periférico que use el código.</p><table tabindex="0"><thead><tr><th>Periférico</th><th>Librería a enlazar</th></tr></thead><tbody><tr><td>GPIO digital</td><td><code>hardware_gpio</code></td></tr><tr><td>PWM</td><td><code>hardware_pwm</code></td></tr><tr><td>I2C</td><td><code>hardware_i2c</code></td></tr><tr><td>SPI</td><td><code>hardware_spi</code></td></tr><tr><td>UART</td><td><code>hardware_uart</code></td></tr><tr><td>ADC</td><td><code>hardware_adc</code></td></tr><tr><td>Timers / alarmas</td><td><code>hardware_timer</code></td></tr><tr><td>Interrupciones</td><td><code>hardware_irq</code></td></tr></tbody></table><p>Usar una función de un periférico en el código (<code>adc_init()</code>, <code>i2c_write_blocking()</code>, etc.) sin haber agregado su librería correspondiente aquí no rompe la compilación — el código compila normal — pero falla en la etapa de <em>linking</em> con errores de símbolo no encontrado.</p><h2 id="project-project-name-c-cxx-asm" tabindex="-1"><code>project(${PROJECT_NAME} C CXX ASM)</code> <a class="header-anchor" href="#project-project-name-c-cxx-asm" aria-label="Permalink to &quot;`project(${PROJECT_NAME}  C CXX ASM)`&quot;">​</a></h2><p>Declara formalmente el proyecto ante CMake. A partir de este punto CMake ya identifica compiladores disponibles. No hace falta declarar lenguajes explícitos (<code>project(nombre C CXX ASM)</code>) — <code>pico_sdk_init()</code>, más abajo, se encarga de habilitarlos internamente.</p><h2 id="pico-sdk-init" tabindex="-1"><code>pico_sdk_init()</code> <a class="header-anchor" href="#pico-sdk-init" aria-label="Permalink to &quot;`pico_sdk_init()`&quot;">​</a></h2><p>El corazón de la integración con el SDK. Agrega como subdirectorio todo el árbol de <code>pico-sdk</code>, expone cada librería (<code>pico_stdlib</code>, <code>hardware_*</code>, etc.) como <em>target</em> de CMake disponible para enlazar, y configura la cadena de compilación cruzada para ARM (RP2040) o ARM/RISC-V (RP2350). Siempre después de <code>project()</code> — llamarlo antes genera una advertencia y comportamiento no garantizado.</p><h2 id="add-executable-project-name-project-sources" tabindex="-1"><code>add_executable(${PROJECT_NAME} ${PROJECT_SOURCES})</code> <a class="header-anchor" href="#add-executable-project-name-project-sources" aria-label="Permalink to &quot;`add_executable(${PROJECT_NAME} ${PROJECT_SOURCES})`&quot;">​</a></h2><p>Comando estándar de CMake (no específico del SDK): declara el binario final y de qué fuentes se compila.</p><h2 id="target-link-libraries-project-name-project-libs" tabindex="-1"><code>target_link_libraries(${PROJECT_NAME} ${PROJECT_LIBS})</code> <a class="header-anchor" href="#target-link-libraries-project-name-project-libs" aria-label="Permalink to &quot;`target_link_libraries(${PROJECT_NAME} ${PROJECT_LIBS})`&quot;">​</a></h2><p>Conecta el ejecutable con las librerías declaradas en <code>PROJECT_LIBS</code>. Aquí es donde el <em>linker</em> resuelve las llamadas del código con su implementación real dentro del SDK.</p><h2 id="pico-add-extra-outputs-project-name" tabindex="-1"><code>pico_add_extra_outputs(${PROJECT_NAME})</code> <a class="header-anchor" href="#pico-add-extra-outputs-project-name" aria-label="Permalink to &quot;`pico_add_extra_outputs(${PROJECT_NAME})`&quot;">​</a></h2><p>Función propia del pico-sdk. A partir del <code>.elf</code> compilado, genera automáticamente los formatos necesarios para trabajar con el hardware:</p><table tabindex="0"><thead><tr><th>Archivo</th><th>Para qué sirve</th></tr></thead><tbody><tr><td><code>.uf2</code></td><td>Flasheo por arrastrar-y-soltar en modo BOOTSEL</td></tr><tr><td><code>.bin</code></td><td>Imagen binaria cruda</td></tr><tr><td><code>.hex</code></td><td>Formato Intel HEX, usado por algunos programadores externos</td></tr><tr><td><code>.map</code></td><td>Mapa de memoria, útil para depurar uso de RAM/Flash</td></tr></tbody></table><p>Sin esta línea solo se genera el <code>.elf</code> — válido para depurar por SWD/OpenOCD, pero no usable para flasheo directo.</p><hr><h2 id="configuracion-opcional-de-stdio" tabindex="-1">Configuración opcional de <code>stdio</code> <a class="header-anchor" href="#configuracion-opcional-de-stdio" aria-label="Permalink to &quot;Configuración opcional de `stdio`&quot;">​</a></h2><p>No forma parte de la plantilla base, pero es común agregarla cuando se necesita consola por USB en vez de por los pines físicos de UART:</p><div class="language-cmake vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmake</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pico_enable_stdio_usb(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">${PROJECT_NAME}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 1)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># activa consola por USB (CDC serial)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pico_enable_stdio_uart(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">${PROJECT_NAME}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 0)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># desactiva salida por pines UART físicos</span></span></code></pre></div><p>Por defecto, sin estas dos líneas, <code>pico_stdlib</code> envía <code>printf()</code> por UART (pines TX/RX físicos). Se activa USB cuando se quiere ver la consola por el mismo cable que ya se usa para flashear, sin conectar un adaptador UART externo.</p>',41)])])}const u=a(o,[["render",d]]);export{k as __pageData,u as default};
